#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,w;
    cin>>n>>w;
    int a[n],f[10001];
    for(int i=0;i<n;i++){
        cin>>a[i];
    }
    for(int i=1;i<=w;i++){
        f[i]=1e9;
    }
    f[0]=0;
    for(int i=1;i<=w;i++){
        for(int j=0;j<n;j++){
            if(a[j]<=i){
                f[i]=min(f[i],f[i-a[j]]+1);
            }
        }
    }
    cout<<f[w];
}
